export class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private lastRefill: number;

  constructor(maxTokens: number, refillRate: number) {
    this.maxTokens = maxTokens;
    this.tokens = maxTokens;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  tryConsume(): boolean {
    this.refill();

    if (this.tokens >= 1) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefill = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefill;

    const newTokens = (elapsed * this.refillRate) / 1000;

    this.tokens = Math.min(this.maxTokens, this.tokens + newTokens);

    this.lastRefill = now;
  }
}

export interface Record {
  id: number;
  name: string;
  category: string;
  value: number;
}

export type Stage = (records: Record[]) => Record[];

export type Filter = (record: Record) => boolean;

export class Pipeline {
  private stages: Stage[] = [];
  private filters: Filter[] = [];

  addStage(stage: Stage): this {
    this.stages.push(stage);
    return this;
  }

  addFilter(filter: Filter): this {
    this.filters.push(filter);
    return this;
  }

  run(records: Record[]): Record[] {
    let result = [...records];

    if (this.filters.length > 0) {
      const combined = andFilter(...this.filters);
      result = result.filter(combined);
    }

    for (const stage of this.stages) {
      result = stage(result);
    }

    return result;
  }
}

export function andFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.every((f) => f(record));
}

export function orFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.some((f) => f(record));
}

export function notFilter(filter: Filter): Filter {
  return (record: Record) => !filter(record);
}

export function doubleValues(records: Record[]): Record[] {
  return records.map((r) => ({ ...r, value: r.value * 2 }));
}

export interface CronSchedule {
  minutes: number[];
  hours: number[];
  daysOfMonth: number[];
  months: number[];
  daysOfWeek: number[];
  original: string;
}

export class CronParseError extends Error {
  constructor(message: string, public field?: string) {
    super(message);
    this.name = 'CronParseError';
  }
}

function parseField(expr: string, min: number, max: number, fieldName: string): number[] {
  const results: number[] = [];

  if (expr === '*') {
    for (let i = min; i <= max; i++) results.push(i);
    return results;
  }

  // Handle comma-separated list
  if (expr.includes(',')) {
    const parts = expr.split(',');
    for (const part of parts) {
      const values = parseField(part.trim(), min, max, fieldName);
      for (const v of values) {
        if (!results.includes(v)) results.push(v);
      }
    }
    results.sort((a, b) => a - b);
    return results;
  }

  // Handle step
  if (expr.includes('/')) {
    const [rangePart, stepStr] = expr.split('/');
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new CronParseError(`Invalid step value in field ${fieldName}: ${expr}`, fieldName);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === '*') {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes('-')) {
      const [startStr, endStr] = rangePart.split('-');
      rangeMin = parseInt(startStr, 10);
      rangeMax = parseInt(endStr, 10);
      if (isNaN(rangeMin) || isNaN(rangeMax)) {
        throw new CronParseError(`Invalid range in field ${fieldName}: ${expr}`, fieldName);
      }
    } else {
      rangeMin = parseInt(rangePart, 10);
      rangeMax = max;
      if (isNaN(rangeMin)) {
        throw new CronParseError(`Invalid value in field ${fieldName}: ${expr}`, fieldName);
      }
    }

    if (rangeMin < min || rangeMax > max || rangeMin > rangeMax) {
      throw new CronParseError(`Out of range in field ${fieldName}: ${expr}`, fieldName);
    }

    for (let i = rangeMin; i <= rangeMax; i += step) {
      results.push(i);
    }
    return results;
  }

  // Handle range
  if (expr.includes('-')) {
    const [startStr, endStr] = expr.split('-');
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new CronParseError(`Invalid range in field ${fieldName}: ${expr}`, fieldName);
    }
    if (start < min || end > max || start > end) {
      throw new CronParseError(`Out of range in field ${fieldName}: ${expr}`, fieldName);
    }
    for (let i = start; i <= end; i++) results.push(i);
    return results;
  }

  // Single value
  const val = parseInt(expr, 10);
  if (isNaN(val)) {
    throw new CronParseError(`Invalid value in field ${fieldName}: ${expr}`, fieldName);
  }
  if (val < min || val > max) {
    throw new CronParseError(`Value ${val} out of range [${min}-${max}] in field ${fieldName}`, fieldName);
  }
  results.push(val);
  return results;
}

export function parseCron(expression: string): CronSchedule {
  if (!expression || typeof expression !== 'string') {
    throw new CronParseError('Expression must be a non-empty string');
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new CronParseError(`Expected 5 fields but got ${fields.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  const minutes = parseField(minuteExpr, 0, 59, 'minute');
  const hours = parseField(hourExpr, 0, 23, 'hour');
  const daysOfMonth = parseField(domExpr, 1, 31, 'day-of-month');
  const months = parseField(monthExpr, 1, 12, 'month');
  const daysOfWeek = parseField(dowExpr, 0, 6, 'day-of-week');

  return {
    minutes,
    hours,
    daysOfMonth,
    months,
    daysOfWeek,
    original: expression.trim(),
  };
}

export interface Item {
  id: string;
  name: string;
  status: "active" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Request {
  method: "GET" | "POST" | "PUT" | "DELETE" | string;
  headers: Record<string, string>;
  params: Record<string, string>;
  body?: unknown;
}

export interface Response {
  status: number;
  body: unknown;
}

const store = new Map<string, Item>();

export function resetStore(): void {
  store.clear();
}

export function getStore(): Map<string, Item> {
  return store;
}

function successResponse(status: number, data: unknown): Response {
  return { status, body: { success: true, data } };
}

function errorResponse(status: number, error: string): Response {
  return { status, body: { success: false, error } };
}

function checkAuth(req: Request): Response | null {
  if (!req.headers["authorization"]) {
    return errorResponse(401, "Authorization required");
  }
  if (req.headers["authorization"] !== "Bearer valid-token") {
    return errorResponse(401, "Invalid token");
  }
  return null;
}

function handleGet(req: Request): Response {
  if (!req.params["id"]) {
    return successResponse(200, Array.from(store.values()));
  }
  const item = store.get(req.params["id"]);
  if (!item) return errorResponse(404, "Item not found");
  return successResponse(200, item);
}

function handlePost(req: Request): Response {
  if (!req.body) return errorResponse(400, "Request body is required");
  const data = req.body as Record<string, unknown>;
  if (!data["name"] || typeof data["name"] !== "string") {
    return errorResponse(400, "Validation failed: name is required");
  }
  const id = data["id"] as string | undefined;
  if (id && store.has(id)) return errorResponse(409, "Item already exists");
  const newId = id || `item-${Date.now()}`;
  const now = Date.now();
  const item: Item = {
    id: newId,
    name: data["name"] as string,
    status: "active",
    createdAt: now,
    updatedAt: now,
  };
  store.set(newId, item);
  return successResponse(201, item);
}

function handlePut(req: Request): Response {
  if (!req.body) return errorResponse(400, "Request body is required");
  if (!req.params["id"]) {
    return errorResponse(400, "Validation failed: id parameter is required");
  }
  const item = store.get(req.params["id"]);
  if (!item) return errorResponse(404, "Item not found");
  const data = req.body as Record<string, unknown>;
  const updated: Item = { ...item, updatedAt: Date.now() };
  if (data["name"] && typeof data["name"] === "string") {
    updated.name = data["name"] as string;
  }
  if (data["status"] === "active" || data["status"] === "archived") {
    updated.status = data["status"] as "active" | "archived";
  }
  store.set(req.params["id"], updated);
  return successResponse(200, updated);
}

function handleDelete(req: Request): Response {
  if (!req.params["id"]) {
    return errorResponse(400, "Validation failed: id parameter is required");
  }
  const item = store.get(req.params["id"]);
  if (!item) return errorResponse(404, "Item not found");
  store.delete(req.params["id"]);
  return successResponse(200, { deleted: req.params["id"] });
}

const methodHandlers: Record<string, (req: Request) => Response> = {
  GET: handleGet,
  POST: handlePost,
  PUT: handlePut,
  DELETE: handleDelete,
};

export function handleRequest(req: Request): Response {
  const authError = checkAuth(req);
  if (authError) return authError;
  const handler = methodHandlers[req.method];
  if (!handler) return errorResponse(405, "Method not allowed");
  return handler(req);
}

import { deepMerge } from "../../starter/deep-merge.js";
import { describe, it, expect } from "vitest";

describe("deepMerge", () => {
  describe("basic merging", () => {
    it("merges two flat objects", () => {
      const target = { a: 1, b: 2 };
      const source = { b: 3, c: 4 };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: 1, b: 3, c: 4 });
    });

    it("returns a new object (does not mutate target)", () => {
      const target = { a: 1 };
      const source = { b: 2 };
      const result = deepMerge(target, source);
      expect(result).not.toBe(target);
      expect(target).toEqual({ a: 1 });
    });

    it("does not mutate source", () => {
      const target = { a: 1 };
      const source = { b: 2 };
      deepMerge(target, source);
      expect(source).toEqual({ b: 2 });
    });

    it("handles empty target", () => {
      const target = {};
      const source = { a: 1 };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: 1 });
    });

    it("handles empty source", () => {
      const target = { a: 1 };
      const source = {};
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: 1 });
    });

    it("handles both empty", () => {
      const result = deepMerge({}, {});
      expect(result).toEqual({});
    });

    it("target keys not in source are preserved", () => {
      const target = { a: 1, b: 2 };
      const source = { c: 3 };
      const result = deepMerge(target, source);
      expect(result.a).toBe(1);
      expect(result.b).toBe(2);
      expect(result.c).toBe(3);
    });
  });

  describe("nested object merging", () => {
    it("recursively merges nested objects", () => {
      const target = { a: { x: 1, y: 2 } };
      const source = { a: { y: 3, z: 4 } };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: { x: 1, y: 3, z: 4 } });
    });

    it("deeply nested merging", () => {
      const target = { a: { b: { c: { d: 1 } } } };
      const source = { a: { b: { c: { e: 2 } } } };
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: { b: { c: { d: 1, e: 2 } } } });
    });

    it("replaces target value with source plain object when target is not plain object", () => {
      const target = { a: 42 };
      const source = { a: { b: 1 } };
      const result = deepMerge(target as any, source as any);
      expect(result.a).toEqual({ b: 1 });
    });

    it("replaces source plain object with non-object when source has non-object", () => {
      const target = { a: { b: 1 } };
      const source = { a: 42 };
      const result = deepMerge(target as any, source as any);
      expect(result.a).toBe(42);
    });

    it("nested objects are not shared by reference", () => {
      const target = { a: { x: 1 } };
      const source = { a: { y: 2 } };
      const result = deepMerge(target, source);
      expect(result.a).not.toBe(target.a);
    });
  });

  describe("null handling", () => {
    it("null in source replaces target value with null", () => {
      const target = { a: 1 };
      const source = { a: null };
      const result = deepMerge(target as any, source as any);
      expect(result.a).toBeNull();
    });

    it("null in source replaces nested object with null", () => {
      const target = { a: { b: 1 } };
      const source = { a: null };
      const result = deepMerge(target as any, source as any);
      expect(result.a).toBeNull();
    });

    it("null in source replaces array with null", () => {
      const target = { a: [1, 2, 3] };
      const source = { a: null };
      const result = deepMerge(target as any, source as any);
      expect(result.a).toBeNull();
    });
  });

  describe("undefined handling", () => {
    it("undefined in source is skipped (target value preserved)", () => {
      const target = { a: 1 };
      const source = { a: undefined };
      const result = deepMerge(target as any, source as any);
      expect(result.a).toBe(1);
    });

    it("undefined in source does not add key when target does not have it", () => {
      const target = { a: 1 };
      const source = { b: undefined };
      const result = deepMerge(target as any, source as any);
      expect(result).toEqual({ a: 1 });
    });
  });

  describe("array handling", () => {
    it("source array replaces target array entirely", () => {
      const target = { a: [1, 2, 3] };
      const source = { a: [4, 5] };
      const result = deepMerge(target, source);
      expect(result.a).toEqual([4, 5]);
    });

    it("source array is a new array (not the same reference)", () => {
      const arr = [1, 2, 3];
      const target = { a: [0] };
      const source = { a: arr };
      const result = deepMerge(target, source);
      expect(result.a).not.toBe(arr);
      expect(result.a).toEqual([1, 2, 3]);
    });

    it("source array replaces non-array target", () => {
      const target = { a: "hello" };
      const source = { a: [1, 2] };
      const result = deepMerge(target as any, source as any);
      expect(result.a).toEqual([1, 2]);
    });

    it("empty source array replaces target array", () => {
      const target = { a: [1, 2, 3] };
      const source = { a: [] };
      const result = deepMerge(target, source);
      expect(result.a).toEqual([]);
    });

    it("array with objects is replaced entirely, not merged", () => {
      const target = { a: [{ x: 1 }, { y: 2 }] };
      const source = { a: [{ z: 3 }] };
      const result = deepMerge(target, source);
      expect(result.a).toEqual([{ z: 3 }]);
    });
  });

  describe("Date handling", () => {
    it("Date in source is cloned", () => {
      const date = new Date("2023-01-01");
      const target = {};
      const source = { d: date };
      const result = deepMerge(target as any, source as any);
      expect(result.d).toEqual(date);
      expect(result.d).not.toBe(date);
    });

    it("cloned Date has same time value", () => {
      const date = new Date(1690000000000);
      const target = {};
      const source = { d: date };
      const result = deepMerge(target as any, source as any);
      expect((result.d as Date).getTime()).toBe(date.getTime());
    });

    it("Date replaces target value", () => {
      const date = new Date("2023-06-15");
      const target = { d: "old value" };
      const source = { d: date };
      const result = deepMerge(target as any, source as any);
      expect(result.d).toBeInstanceOf(Date);
      expect((result.d as Date).getTime()).toBe(date.getTime());
    });

    it("mutating source date does not affect result", () => {
      const date = new Date("2023-01-01");
      const target = {};
      const source = { d: date };
      const result = deepMerge(target as any, source as any);
      date.setFullYear(2000);
      expect((result.d as Date).getFullYear()).toBe(2023);
    });
  });

  describe("Symbol key support", () => {
    it("merges symbol keys from source", () => {
      const sym = Symbol("key");
      const target = { a: 1 };
      const source = { [sym]: "symbolValue" };
      const result = deepMerge(target as any, source as any);
      expect(result[sym]).toBe("symbolValue");
    });

    it("symbol keys in target are preserved", () => {
      const sym = Symbol("key");
      const target = { [sym]: "targetSymbol" };
      const source = { a: 1 };
      const result = deepMerge(target as any, source as any);
      expect(result[sym]).toBe("targetSymbol");
    });

    it("source symbol overwrites target symbol", () => {
      const sym = Symbol("key");
      const target = { [sym]: "old" };
      const source = { [sym]: "new" };
      const result = deepMerge(target as any, source as any);
      expect(result[sym]).toBe("new");
    });

    it("multiple symbol keys are merged", () => {
      const sym1 = Symbol("a");
      const sym2 = Symbol("b");
      const target = { [sym1]: 1 };
      const source = { [sym2]: 2 };
      const result = deepMerge(target as any, source as any);
      expect(result[sym1]).toBe(1);
      expect(result[sym2]).toBe(2);
    });
  });

  describe("prototype pollution protection", () => {
    it("ignores __proto__ key", () => {
      const target = { a: 1 };
      const malicious = JSON.parse('{"__proto__": {"polluted": true}}');
      const result = deepMerge(target, malicious);
      expect((result as any).polluted).toBeUndefined();
      expect(({} as any).polluted).toBeUndefined();
    });

    it("ignores constructor key", () => {
      const target = { a: 1 };
      const source: any = {};
      Object.defineProperty(source, "constructor", {
        value: { prototype: { polluted: true } },
        enumerable: true,
      });
      const result = deepMerge(target, source);
      expect((result as any).constructor).toBe(Object);
    });

    it("ignores prototype key", () => {
      const target = { a: 1 };
      const source: any = { prototype: { polluted: true } };
      deepMerge(target, source);
      expect((Object as any).polluted).toBeUndefined();
    });

    it("__proto__ key does not appear in result's own properties", () => {
      const target = {};
      const source = JSON.parse('{"__proto__": {"x": 1}}');
      const result = deepMerge(target, source);
      expect(Object.keys(result)).not.toContain("__proto__");
    });

    it("constructor key does not overwrite constructor in result", () => {
      const target = {};
      const source: any = { constructor: "hacked" };
      const result = deepMerge(target, source);
      expect(result.constructor).toBe(Object);
    });
  });

  describe("complex scenarios", () => {
    it("merges deeply nested with multiple levels", () => {
      const target = {
        level1: {
          level2: {
            level3: { a: 1, b: 2 },
          },
        },
      };
      const source = {
        level1: {
          level2: {
            level3: { b: 99, c: 3 },
          },
        },
      };
      const result = deepMerge(target, source);
      expect(result.level1.level2.level3).toEqual({ a: 1, b: 99, c: 3 });
    });

    it("handles mixed types: nested object, array, date, null, primitive", () => {
      const date = new Date("2024-01-01");
      const target = {
        obj: { x: 1 },
        arr: [1, 2],
        date: new Date("2020-01-01"),
        num: 5,
        nil: "something",
      };
      const source = {
        obj: { y: 2 },
        arr: [3, 4, 5],
        date,
        num: 10,
        nil: null,
      };
      const result = deepMerge(target as any, source as any);
      expect(result.obj).toEqual({ x: 1, y: 2 });
      expect(result.arr).toEqual([3, 4, 5]);
      expect((result.date as Date).getTime()).toBe(date.getTime());
      expect(result.date).not.toBe(date);
      expect(result.num).toBe(10);
      expect(result.nil).toBeNull();
    });

    it("string values in source overwrite target", () => {
      const target = { a: "hello" };
      const source = { a: "world" };
      const result = deepMerge(target, source);
      expect(result.a).toBe("world");
    });

    it("boolean false in source overwrites target", () => {
      const target = { a: true };
      const source = { a: false };
      const result = deepMerge(target, source);
      expect(result.a).toBe(false);
    });

    it("number 0 in source overwrites target", () => {
      const target = { a: 99 };
      const source = { a: 0 };
      const result = deepMerge(target, source);
      expect(result.a).toBe(0);
    });

    it("nested object in source replaces primitive in target", () => {
      const target = { a: 5 };
      const source = { a: { nested: true } };
      const result = deepMerge(target as any, source as any);
      expect(result.a).toEqual({ nested: true });
    });

    it("deep merge does not affect other top-level keys", () => {
      const target = { a: { x: 1 }, b: "keep" };
      const source = { a: { y: 2 } };
      const result = deepMerge(target, source);
      expect(result.b).toBe("keep");
    });

    it("result contains all keys from both target and source", () => {
      const target = { a: 1, b: 2, c: 3 };
      const source = { d: 4, e: 5 };
      const result = deepMerge(target as any, source as any);
      expect(Object.keys(result).sort()).toEqual(["a", "b", "c", "d", "e"]);
    });

    it("null prototype objects are treated as plain objects", () => {
      const nullProtoObj = Object.create(null) as Record<string, unknown>;
      nullProtoObj.a = 1;
      const target = { obj: { b: 2 } };
      const source = { obj: nullProtoObj };
      const result = deepMerge(target as any, source as any);
      expect(result.obj).toEqual({ a: 1, b: 2 });
    });

    it("handles source with many keys", () => {
      const target = {};
      const source: Record<string, number> = {};
      for (let i = 0; i < 100; i++) {
        source[`key${i}`] = i;
      }
      const result = deepMerge(target as any, source);
      for (let i = 0; i < 100; i++) {
        expect(result[`key${i}`]).toBe(i);
      }
    });
  });

  describe("non-plain objects in source", () => {
    it("non-plain object (class instance) in source is assigned directly", () => {
      class Foo {
        bar = 42;
      }
      const foo = new Foo();
      const target = { a: 1 };
      const source = { foo };
      const result = deepMerge(target as any, source as any);
      expect(result.foo).toBe(foo);
    });

    it("RegExp in source is assigned directly", () => {
      const re = /test/g;
      const target = {};
      const source = { re };
      const result = deepMerge(target as any, source as any);
      expect(result.re).toBe(re);
    });

    it("function in source is assigned directly", () => {
      const fn = () => 42;
      const target = {};
      const source = { fn };
      const result = deepMerge(target as any, source as any);
      expect(result.fn).toBe(fn);
    });
  });

  describe("target is not modified", () => {
    it("original target nested object is not modified", () => {
      const nested = { x: 1 };
      const target = { a: nested };
      const source = { a: { y: 2 } };
      deepMerge(target, source);
      expect(nested).toEqual({ x: 1 });
      expect(target.a).toBe(nested);
    });

    it("original target array is not modified", () => {
      const arr = [1, 2, 3];
      const target = { a: arr };
      const source = { a: [4, 5, 6] };
      deepMerge(target, source);
      expect(arr).toEqual([1, 2, 3]);
    });
  });
});
